insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('e48cc637-330e-4625-8c8c-c90de4bd9736', '9db41a66-a367-4f5f-aa3a-1087d441b6de', $$standaardomstandigheden en vorming van cadmiumgeel (CdS)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context1.png$$,
   $$Tenzij anders vermeld is er sprake van standaardomstandigheden (T = 298 K en p = p⁰).

In de negentiende en begin twintigste eeuw ontwikkelde de chemische industrie veel nieuwe pigmenten, zoals cadmiumgeel (cadmiumsulfide, CdS). Cadmiumgeel werd onder andere gemaakt door de reactie van cadmiumcarbonaat met zwavel (S). Bij deze reactie ontstaan behalve cadmiumsulfide ook zwaveldioxide en koolstofdioxide.$$, 'inline'),
  ('5098cf5e-864c-436f-84f7-7b5f48f2e8ba', '9db41a66-a367-4f5f-aa3a-1087d441b6de', $$scheiding van overmaat zwavel door verwarming$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context2.png$$,
   $$Bij deze productie werd zwavel in overmaat toegevoegd. De overgebleven zwavel kon na afloop van de reactie gemakkelijk worden gescheiden van de gevormde cadmiumsulfide door het verkregen mengsel te verwarmen. Hierbij verdampt de zwavel, maar de cadmiumsulfide niet.$$, 'inline'),
  ('c3b3c674-a77a-4f6f-9673-9af5f59c437c', '9db41a66-a367-4f5f-aa3a-1087d441b6de', $$aantastingen van cadmiumgeel op schilderijen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context3.png$$,
   $$Helaas bleek cadmiumgeel op de lange termijn niet chemisch stabiel. Op verschillende schilderijen zijn drie opeenvolgende aantastingen van cadmiumgeel waargenomen:
− verbleking door de vorming van cadmiumsulfaat.
− de vorming van kleine witte vlekken waarin vooral cadmiumsulfaatmonohydraat aanwezig is.
− verkleuring door onder andere de vorming van lood(II)sulfaat (PbSO₄). Deze verkleuring trad alleen op nadat vernis was aangebracht op een al aangetast schilderij.

De omzetting van cadmiumgeel met zuurstof tot cadmiumsulfaatmonohydraat treedt alleen op in vochtige lucht.$$, 'inline'),
  ('9d1b0e9b-4f6c-49d1-a6b1-9777bae24484', '9db41a66-a367-4f5f-aa3a-1087d441b6de', $$ontdekking van een tweede zout in de witte vlekken$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context4.png$$,
   $$Behalve cadmiumsulfaatmonohydraat ontdekte men in de witte vlekken een ander zout. In dit zout zijn cadmiumionen en sulfaationen in de molverhouding 2 : 3 aanwezig. Behalve deze ionen is er nog één andere ionsoort aanwezig. Op grond van de gevonden samenstelling van het zout vermoedden de onderzoekers dat een van de schilderijen ooit met een oplossing van ammoniak is schoongemaakt.$$, 'inline'),
  ('cc80db0c-65b3-4074-b608-b8981031115d', '9db41a66-a367-4f5f-aa3a-1087d441b6de', $$evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄²⁻ en Ks-tabel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context5.png$$,
   $$Tijdens periodes met hoge luchtvochtigheid lossen de zouten die in een verflaag aanwezig zijn enigszins op. Dit wordt veroorzaakt doordat zich dan bijvoorbeeld het evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄²⁻ kan instellen in de verflaag. De gehydrateerde ionen kunnen vervolgens door verf- en vernislagen heen bewegen.

Voor het evenwicht CdSO₄ ⇌ Cd²⁺ + SO₄²⁻ geldt Ks = [Cd²⁺][SO₄²⁻]. Ks is het zogenoemde oplosbaarheidsproduct. De waardes van Ks van enkele stoffen zijn in de tabel gegeven.

tabel — stof, formule, Ks = …, waarde van Ks:
cadmiumsulfaat, CdSO₄, [Cd²⁺][SO₄²⁻], 5,3·10⁻¹
lood(II)sulfaat, PbSO₄, [Pb²⁺][SO₄²⁻], 1,7·10⁻⁸
lood(II)ethanoaat, Pb(CH₃COO)₂, [Pb²⁺][CH₃COO⁻]², 2·10¹$$, 'inline'),
  ('911941aa-c560-4804-91b3-bf1e875d5314', '9db41a66-a367-4f5f-aa3a-1087d441b6de', $$vernislaag met lood(II)ethanoaat en aangetroffen PbSO₄$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-context6.png$$,
   $$Op een schilderij waar het cadmiumgeel al deels was omgezet tot cadmiumsulfaat, is in het verleden een laag vernis aangebracht. De gebruikte vernis bevatte als enige loodverbinding lood(II)ethanoaat (Pb(CH₃COO)₂). Zowel in de verflaag als in de vernislaag is door de onderzoekers vast lood(II)sulfaat (PbSO₄) aangetroffen.$$, 'inline'),
  ('ad206912-fd09-416b-8c47-1426e44df396', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', $$Merox-proces — intro (R–SH, lpg)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context1.png$$,
   $$Het Merox-proces is een industrieel proces om zwavelhoudende verbindingen te verwijderen uit aardolieproducten zoals lpg. Lpg is een mengsel van koolwaterstoffen met een laag kookpunt. De zwavelhoudende verbindingen kunnen worden aangeduid met R–SH, waarbij de groep R staat voor een koolwaterstofketen. In figuur 1 is het blokschema van het Merox-proces onvolledig weergegeven.$$, 'inline'),
  ('e89ea3aa-057d-4ac6-a987-07cb0b6be83c', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', $$figuur 1 — blokschema Merox-proces (R1, R2)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context2.png$$,
   $$figuur 1: onvolledig blokschema van het Merox-proces. Natronloog en onzuiver lpg stromen R1 in; uit R1 stroomt gezuiverd lpg omhoog weg, en onderin stroomt een gecombineerde stroom natronloog/NaRS-oplossing door naar R2. Uit R2 stroomt een stof weg die is aangeduid met *.$$, 'inline'),
  ('56869188-5cc6-46ae-a6d8-5903bf26292c', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', $$reactie 1 in R1 en de scheidingsmethode$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context3.png$$,
   $$Het is niet mogelijk om lpg en R–SH te scheiden met behulp van water. Daarom wordt het gasvormige, nog onzuivere lpg in reactor 1 (R1) in contact gebracht met een overmaat natronloog. In R1 reageren de zwavelhoudende verbindingen volgens reactie 1:

R–SH (g) + OH⁻ (aq) → R–S⁻ (aq) + H₂O (l)   (reactie 1)

In een basische oplossing kunnen de zwavelhoudende verbindingen wel van het lpg worden afgescheiden. Dit wordt veroorzaakt door de vorming van bindingen tussen watermoleculen en deeltjes die in R1 zijn ontstaan.$$, 'inline'),
  ('bf21eb85-c44e-4387-951f-15cc6907ba1c', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', $$reactor 2 (R2) en de totaalvergelijking$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context4.png$$,
   $$Het reactiemengsel wordt onderin R1 afgetapt en doorgevoerd naar reactor 2 (R2). In R2 wordt een overmaat lucht door de oplossing afkomstig van R1 geleid, waarbij disulfides (R–S–S–R) worden gevormd. De totaalvergelijking van de reacties die in R1 en R2 verlopen, is hieronder weergegeven:

4 R–SH + O₂ → 2 R–S–S–R + 2 H₂O   (totaalreactie)$$, 'inline'),
  ('262994eb-baa7-40c8-8cfd-6f99888b2f92', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', $$figuur 2 — omzetting butaanthiol in de tijd$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context5.png$$,
   $$In een onderzoek is de omzettingssnelheid van R–SH tot R–S–S–R nader onderzocht. Men onderzocht de omzetting van butaanthiol (C₄H₁₀S) in natronloog. Hierbij werd op verschillende tijdstippen de fractie [C₄H₁₀S]t / [C₄H₁₀S]₀ bepaald. In figuur 2 zijn de resultaten van een meting weergegeven (fractie onomgezet butaanthiol uitgezet tegen de tijd in uren).$$, 'inline'),
  ('a25803df-9319-4555-9f6c-eb58e3668a03', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', $$beginconcentratie en dichtheid van het reactiemengsel$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context6.png$$,
   $$Op t = 0 bevatte het mengsel 372 massa-ppm butaanthiol. De molaire massa van butaanthiol is 90,2 g mol⁻¹. De dichtheid van het reactiemengsel was 0,75 kg L⁻¹.$$, 'inline'),
  ('24a41e92-7aa9-4320-b5f2-4dcb78c1fcaf', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', $$scheidingsruimte 1 (S1) en hergebruik van natronloog$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context7.png$$,
   $$In scheidingsruimte 1 (S1) wordt het vloeibare mengsel afkomstig uit R2 gescheiden. De laag met daarin de vloeibare disulfides (R–S–S–R) wordt als afval afgevoerd. De laag met natronloog bevat geen organische stoffen, zodat het natronloog kan worden hergebruikt in het proces. Om de reactie in R1 steeds onder gelijke omstandigheden te laten verlopen, moet het natronloog een bewerking ondergaan voordat het kan worden teruggevoerd.$$, 'inline'),
  ('fbdc7f3d-713e-4ed5-83fb-5c3c22ca9692', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', $$uitwerkbijlage vraag 12 — onvolledig blokschema R1/R2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-context8.png$$,
   $$uitwerkbijlage bij vraag 12: onvolledig blokschema. Weergegeven zijn de instroom van natronloog en onzuiver lpg in R1, de uitstroom van lpg uit R1, en een gecombineerde stroom natronloog/NaRS-oplossing van R1 naar R2, met bij R2 een uitgaande stroom die is aangeduid met *. De scheidingsruimte(n) en de stofstromen die nodig zijn voor het hergebruik van natronloog (inclusief de teruggevoerde stroom naar R1) ontbreken nog en moeten door de kandidaat worden ingetekend.$$, 'uitwerkbijlage'),
  ('bb092fe8-2259-4b5e-ba5c-d2df0c2cb7e9', '4c30e96f-123e-4446-b58d-0b5957a2f679', $$productie van t-EPDM en structuurformule ENB$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context1.png$$,
   $$EPDM-rubber is een synthetische rubbersoort, die veel wordt gebruikt in de auto-industrie voor bijvoorbeeld afdichtingsstrips en raamrubbers. Bij de productie van EPDM-rubber wordt eerst thermoplastisch EPDM (t-EPDM) gemaakt. Hierbij ondergaat een mengsel van etheen, propeen en een zogeheten dieen een additie-polymerisatie. Een veelgebruikt dieen hierbij is ethylideen-norborneen (ENB). De structuurformule van ENB is hiernaast weergegeven: een bicyclisch norborneen-ringsysteem met een C=C-binding in de ring, en aan de ring een zijketen –CH=CH–CH₃ (ethylideengroep). Bij de vorming van t-EPDM reageert alleen de C=C-binding die zich in de ring bevindt.$$, 'inline'),
  ('5ffe4dd0-eab9-46a3-ad30-2a9892c559bc', '4c30e96f-123e-4446-b58d-0b5957a2f679', $$katalysatortypes en kristallijne gebieden in t-EPDM$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context2.png$$,
   $$De polymerisatie tot t-EPDM verloopt onder invloed van een katalysator. Er zijn twee types katalysator beschikbaar:
− Type 1: hiermee wordt de vorming van een willekeurig (random) copolymeer bevorderd.
− Type 2: hiermee wordt de vorming van een blok-copolymeer bevorderd.

Het blijkt dat de keuze van het type katalysator een sterke invloed heeft op de vorming van kristallijne gebieden in het t-EPDM. In een kristallijn gebied vertonen de polymeerketens een grote mate van ordening. In t-EPDM zijn geen crosslinks aanwezig tussen de polymeerketens.$$, 'inline'),
  ('da686a77-75e2-4571-b6d7-df25cc740dbf', '4c30e96f-123e-4446-b58d-0b5957a2f679', $$vervormbaarheid versus kristallijne gebieden$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context3.png$$,
   $$De vervormbaarheid van t-EPDM wordt minder naarmate het materiaal meer kristallijne gebieden bevat.$$, 'inline'),
  ('06c40df6-41dc-40b9-97c1-a7529aac9c1c', '4c30e96f-123e-4446-b58d-0b5957a2f679', $$productie van EPDM-rubber uit bio-ethanol (reactie 1)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context4.png$$,
   $$Het t-EPDM wordt vervolgens omgezet tot het eindproduct EPDM-rubber. Tot voor kort werd EPDM-rubber geproduceerd op basis van fossiele grondstoffen. In Brazilië gebruikt men nu bio-ethanol uit suikerriet in plaats van aardolie als grondstof voor het benodigde etheen. De omzetting van ethanol tot etheen is hieronder weergegeven:

C₂H₆O (l) → C₂H₄ (g) + H₂O (l)   (reactie 1)$$, 'inline'),
  ('b92b794f-c304-4303-bc7d-428972539147', '4c30e96f-123e-4446-b58d-0b5957a2f679', $$Keltan®-Eco en het gehalte ¹⁴C$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context5.png$$,
   $$Het etheen afkomstig uit reactie 1 wordt vervolgens gebruikt om EPDM-rubber te produceren onder de merknaam Keltan®-Eco. Biogebaseerde producten worden gecontroleerd om misbruik van belastingvoordelen te voorkomen. Hiertoe wordt het gehalte ¹⁴C-atomen in het product bepaald. ¹⁴C-atomen worden in de atmosfeer door kosmische straling gevormd uit ¹⁴N-atomen. Uit de ¹⁴C-atomen wordt in de atmosfeer snel ¹⁴CO gevormd. Het gehalte ¹⁴C in de atmosfeer is constant. Het gehalte ¹⁴C in biomassa bedraagt hierdoor gemiddeld 1,5·10⁻⁶ ppm van alle C-atomen. De ¹⁴C-atomen worden in de loop van de tijd door radioactief verval omgezet tot ¹⁴N-atomen.$$, 'inline'),
  ('64f9bb33-4a3d-4e3f-890b-c23e2ddb5cb3', '4c30e96f-123e-4446-b58d-0b5957a2f679', $$reactie 1 is endotherm — energie uit suikerriet-resten$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context6.png$$,
   $$Reactie 1 is endotherm. De benodigde warmte wordt in het proces geleverd door verbranding van de resten van het suikerriet.$$, 'inline'),
  ('406b80c3-d93b-4074-acb5-76688c9dbd38', '4c30e96f-123e-4446-b58d-0b5957a2f679', $$aluminiumoxide-katalysator — OH- en O⁻-groepen aan het oppervlak$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context7.png$$,
   $$De omzetting van ethanol tot etheen vindt plaats aan het oppervlak van een aluminiumoxide-katalysator. Op de uitwerkbijlage is een deel van het oppervlak weergegeven. Uit onderzoek is gebleken dat de OH-groepen en de O⁻-groepen aan het oppervlak een belangrijke rol spelen in de katalytische werking. Men vermoedt dat hierbij waterstofbruggen worden gevormd tussen moleculen ethanol en de aanwezige groepen op het oppervlak.$$, 'inline'),
  ('952cfb3b-f2f5-4713-b2f1-f85e3fa38ed1', '4c30e96f-123e-4446-b58d-0b5957a2f679', $$monomeerverhoudingen in Keltan®-Eco$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context8.png$$,
   $$Per mol monomeereenheden van Keltan®-Eco is gemiddeld 0,55 mol etheen, 0,40 mol propeen (C₃H₆) en 0,050 mol ENB aanwezig.$$, 'inline'),
  ('910e27b3-ac1f-4563-8bfb-74f11e4c34db', '4c30e96f-123e-4446-b58d-0b5957a2f679', $$uitwerkbijlage vraag 18 — oppervlak van de katalysator$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-context9.png$$,
   $$uitwerkbijlage bij vraag 18: een deel van het oppervlak van de aluminiumoxide-katalysator, met daarop enkele Al-atomen waaraan al OH-groepen en O⁻-groepen zitten, en al twee losse H-atomen die via een stippellijn (waterstofbrug) aan twee van die groepen zijn gebonden. De kandidaat moet een molecuul ethanol tekenen dat met twee waterstofbruggen (elk als stippellijn) aan het oppervlak is gebonden.$$, 'uitwerkbijlage'),
  ('2dbdaced-ac28-42a0-9872-7a1ccec5fed3', 'd42b6847-8518-44d4-81d6-59c37385d94e', $$transglutaminase (TG) en peptidekoppeling$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context1.png$$,
   $$In de voedselindustrie wordt soms het enzym transglutaminase (TG) gebruikt om reststukjes vlees aan elkaar te lijmen tot grotere stukken. Het enzym katalyseert de koppeling van de restgroepen van de aminozuureenheden glutamine en lysine die aanwezig zijn in peptideketens.$$, 'inline'),
  ('c1b31566-616a-47df-aea2-845cb9bbb312', 'd42b6847-8518-44d4-81d6-59c37385d94e', $$figuur 1 — koppeling glutamine- en lysine-restgroep$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context2.png$$,
   $$In figuur 1 is de koppeling van de restgroepen van een glutamine-eenheid en een lysine-eenheid in verschillende peptideketens schematisch en onvolledig weergegeven: de restgroep ~CH₂-CH₂-C(=O)-NH₂ van de glutamine-eenheid reageert met de restgroep H₃N⁺-CH₂~ van de lysine-eenheid, in evenwicht met het gekoppelde product ~CH₂-CH₂-C(=O)-N(H)-CH₂~ en een deeltje X.$$, 'inline'),
  ('4f7bbd63-2202-47f4-b37c-f482141cd82e', 'd42b6847-8518-44d4-81d6-59c37385d94e', $$reactie van glutamine-restgroep met water (uitwerkbijlage vraag 22)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context3.png$$,
   $$Wanneer geen lysine-restgroepen of ongebonden aminozuren beschikbaar zijn, katalyseert TG ook de reactie tussen de restgroep van glutamine-eenheden en water. Hierbij wordt een andere aminozuur-eenheid gevormd en ontstaat ammoniak. Deze omzetting is op de uitwerkbijlage onvolledig weergegeven.$$, 'inline'),
  ('e337778e-2643-46ab-881b-f4ec75395789', 'd42b6847-8518-44d4-81d6-59c37385d94e', $$lading van de lysine-restgroep en Kz van de ~NH₃⁺-groep$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context4.png$$,
   $$De koppeling die in de figuur is weergegeven, verloopt in een breed pH-gebied. De reactie verloopt alleen als de restgroep van de lysine-eenheid positief geladen is. Bij de gemiddelde pH van bloed zijn de aminogroepen in de restgroepen van lysine-eenheden grotendeels omgezet tot ~NH₃⁺-groepen. De waarde van de Kz van de ~NH₃⁺-groep is 6,3·10⁻¹¹.$$, 'inline'),
  ('c2400048-09fc-409a-9ee0-24a23ef66d1e', 'd42b6847-8518-44d4-81d6-59c37385d94e', $$NH₂-groep van glutamine als zwakkere base — grensstructuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context5.png$$,
   $$De NH₂-groep in de restgroep van glutamine is een veel zwakkere base dan de NH₂-groep in de restgroep van lysine. Dit kan worden verklaard met behulp van een grensstructuur van de restgroep van glutamine. In deze grensstructuur komen formele ladingen voor. Op de uitwerkbijlage is deze grensstructuur onvolledig weergegeven.$$, 'inline'),
  ('9c2174f7-3cc2-4d46-a250-68ea068e0222', 'd42b6847-8518-44d4-81d6-59c37385d94e', $$reactiemechanisme met His373 en Cys314$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context6.png$$,
   $$In het reactiemechanisme van de koppeling van glutamine en lysine door TG spelen twee aminozuureenheden in het actieve centrum van TG een rol: His373 en Cys314. Op de uitwerkbijlage is een stap uit dit mechanisme onvolledig weergegeven. In deze stap wordt een eenheid Lys gekoppeld aan een eenheid Gln die al aan aminozuureenheid Cys314 van TG was gekoppeld.$$, 'inline'),
  ('eb3a2cd6-e023-4cf4-a5f0-c618c5344af1', 'd42b6847-8518-44d4-81d6-59c37385d94e', $$uitwerkbijlage vraag 22 — reactie glutamine-restgroep met water$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context7.png$$,
   $$uitwerkbijlage bij vraag 22: onvolledig weergegeven reactie van de restgroep van een glutamine-eenheid (~CH₂-CH₂-C(=O)-NH₂) met water, met een pijl omhoog naar het ontstane ammoniak en een aanduiding van de ontstane aminozuureenheid; de kandidaat moet de vergelijking compleet maken en de naam van de ontstane aminozuureenheid invullen.$$, 'uitwerkbijlage'),
  ('5e7bb5e1-7dd8-4011-803f-6cd29fd5263b', 'd42b6847-8518-44d4-81d6-59c37385d94e', $$uitwerkbijlage vraag 24 — grensstructuur restgroep glutamine$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context8.png$$,
   $$uitwerkbijlage bij vraag 24: de restgroep van glutamine (met de C(=O)-NH-groep) onvolledig weergegeven als grensstructuur; de kandidaat moet de ontbrekende elektronenparen tekenen en de formele ladingen aangeven.$$, 'uitwerkbijlage'),
  ('d529877a-3aca-4eb5-9ecb-7b88c9d9ab00', 'd42b6847-8518-44d4-81d6-59c37385d94e', $$uitwerkbijlage vraag 25 — reactiemechanisme His373/Cys314$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-context9.png$$,
   $$uitwerkbijlage bij vraag 25: een stap uit het reactiemechanisme, met links His373 en Cys314 (met de restgroep van Gln als S-C(=O)-Gln aan Cys314 gekoppeld) en de restgroep van Lys ernaast, en rechts (na de pijl) het resultaat waarbij His373 positief geladen is en Lys via een nieuwe N–C-binding aan de Gln-eenheid is gekoppeld, met een negatieve lading op het zuurstofatoom van Gln; de kandidaat moet links van de pijl de niet-bindende elektronenparen tekenen en met vloeipijlen de verplaatsing van elektronenparen tijdens de reactie weergeven.$$, 'uitwerkbijlage');

insert into practice_questions (id, exercise_id, question_number, topics, question_image_url, question_text, context_block_ids) values
  ('1791f46d-81f2-45f5-a2ec-b91972699e26', '9db41a66-a367-4f5f-aa3a-1087d441b6de', 1,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag1.png$$, $$Geef de vergelijking van deze vorming van cadmiumsulfide uit zwavel en cadmiumcarbonaat.$$, array['e48cc637-330e-4625-8c8c-c90de4bd9736']::uuid[]),
  ('3b5f981f-caf3-4661-a6da-5f4976e9bd5b', '9db41a66-a367-4f5f-aa3a-1087d441b6de', 2,
   '[{"domain": "Rekenen en analyse", "subdomain": "Molaire massa en molariteit"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag2.png$$, $$Bereken de massa in gram zwavel die minimaal nodig is om 1,0 kg cadmiumcarbonaat volledig om te zetten tot cadmiumsulfide. Geef de uitkomst in het juiste aantal significante cijfers.$$, array['e48cc637-330e-4625-8c8c-c90de4bd9736']::uuid[]),
  ('ed2f1172-5bb9-4cf8-a089-1f214098a247', '9db41a66-a367-4f5f-aa3a-1087d441b6de', 3,
   '[{"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag3.png$$, $$Leg uit dat zwavel bij een lagere temperatuur verdampt dan cadmiumsulfide. Neem hier aan dat zwavel bestaat uit deeltjes S₈.
− Gebruik hierbij begrippen op microniveau.
− Benoem de bindingstypes in beide stoffen.$$, array['5098cf5e-864c-436f-84f7-7b5f48f2e8ba']::uuid[]),
  ('07b2c3f4-d912-4799-879e-be70bf309ceb', '9db41a66-a367-4f5f-aa3a-1087d441b6de', 4,
   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag4.png$$, $$Geef de vergelijking van de omzetting van cadmiumgeel tot cadmiumsulfaatmonohydraat.$$, array['e48cc637-330e-4625-8c8c-c90de4bd9736', 'c3b3c674-a77a-4f6f-9673-9af5f59c437c']::uuid[]),
  ('bd08cac5-cf1e-40bf-a8b8-7ced0685428e', '9db41a66-a367-4f5f-aa3a-1087d441b6de', 5,
   '[{"domain": "Materie", "subdomain": "Bindingen en stofeigenschappen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag5.png$$, $$Geef een mogelijke verhoudingsformule van het gevonden zout.$$, array['c3b3c674-a77a-4f6f-9673-9af5f59c437c', '9d1b0e9b-4f6c-49d1-a6b1-9777bae24484']::uuid[]),
  ('3cd4b27a-83ee-4c5f-8f73-4c1a20550ea8', '9db41a66-a367-4f5f-aa3a-1087d441b6de', 6,
   '[{"domain": "Reacties", "subdomain": "Chemisch evenwicht en evenwichtsconstante"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag6.png$$, $$Leg uit, onder andere met behulp van evenwichtsbeschouwingen, dat lood(II)sulfaat aanwezig is in de vernislaag als gevolg van periodes met hoge luchtvochtigheid. Neem aan dat de waardes in de tabel ook gelden onder de omstandigheden in een verflaag tijdens periodes van hoge luchtvochtigheid.$$, array['cc80db0c-65b3-4074-b608-b8981031115d', '911941aa-c560-4804-91b3-bf1e875d5314']::uuid[]),
  ('586dff9e-b03a-45f9-8bbe-a59a5b64c619', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', 7,
   '[{"domain": "Rekenen en analyse", "subdomain": "Scheidingstechnieken (filteren, destilleren, extraheren)"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag7.png$$, $$Geef de naam van de scheidingsmethode die wordt toegepast in R1.$$, array['ad206912-fd09-416b-8c47-1426e44df396', '56869188-5cc6-46ae-a6d8-5903bf26292c']::uuid[]),
  ('e5753600-5a68-497c-89bb-bca8b906f2b9', '9942b497-2e2a-4fd1-90a8-61eb61a2381d', 8,
