   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag9.png$$, $$Geef de vergelijking van de reactie die verloopt in R2.$$, array['56869188-5cc6-46ae-a6d8-5903bf26292c', 'bf21eb85-c44e-4387-951f-15cc6907ba1c']::uuid[]),
