− Waar in het blokschema een * voorkomt, hoef je niets aan te geven.$$, array['e89ea3aa-057d-4ac6-a987-07cb0b6be83c', 'bf21eb85-c44e-4387-951f-15cc6907ba1c', '24a41e92-7aa9-4320-b5f2-4dcb78c1fcaf', 'fbdc7f3d-713e-4ed5-83fb-5c3c22ca9692']::uuid[]),
  ('466b78ec-c5ee-4fde-8ffb-50aa9b3b2d0a', '4c30e96f-123e-4446-b58d-0b5957a2f679', 13,
