   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag21.png$$, $$Geef de formule van het deeltje X.$$, array['c1b31566-616a-47df-aea2-845cb9bbb312']::uuid[]),
