   '[{"domain": "Reacties", "subdomain": "Reactievergelijkingen opstellen"}]'::jsonb,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag22.png$$, $$Maak de vergelijking op de uitwerkbijlage compleet en geef de naam van de aminozuureenheid die hierbij wordt gevormd.$$, array['4f7bbd63-2202-47f4-b37c-f482141cd82e', 'eb3a2cd6-e023-4cf4-a5f0-c618c5344af1']::uuid[]),
