   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag23.png$$, $$Laat met een berekening zien dat bij pH = 7,40 het percentage aminogroepen van lysine-eenheden dat aanwezig is als ~NH₂ kleiner is dan 2,0%.$$, array['e337778e-2643-46ab-881b-f4ec75395789']::uuid[]),
  ('d5833eaf-2c3d-4338-8189-dd62ba41bf9c', 'd42b6847-8518-44d4-81d6-59c37385d94e', 24,
